<!doctype html><html><head><meta charset="utf-8"><title>{{ ucfirst($type) }} Report</title><style>body{font-family:Arial,sans-serif;color:#222;font-size:12px}h1{margin-bottom:4px}.muted{color:#777}.summary{display:flex;gap:20px;margin:20px 0}.box{border:1px solid #ddd;padding:10px 16px}table{width:100%;border-collapse:collapse}th,td{border:1px solid #ddd;padding:8px;text-align:left}th{background:#f4b400}@media print{button{display:none}}</style></head><body><button onclick="window.print()">Print report</button><h1>{{ ucfirst($type) }} report</h1><div class="muted">Generated {{ now()->format('d M Y, h:i A') }}</div><div class="summary">@foreach($summary as $label=>$value)<div class="box"><small>{{ $label }}</small><br><strong>{{ is_numeric($value)?number_format($value,2):$value }}</strong></div>@endforeach</div><table><thead><tr>@foreach($columns as $column)<th>{{ $column }}</th>@endforeach</tr></thead><tbody>@foreach($rows as $row)<tr>@foreach($row as $value)<td>{{ $value }}</td>@endforeach</tr>@endforeach</tbody></table></body></html>
